  ('pukao-e3452428-moex-00534', 'pukao-e3452428', 'pukao-e3452428-moex-111-d1a761c9', 'sub-pukao-e3452428-03', NULL, 'single_choice', '關於行政處分程序重開之敘述，下列何者正確？', '["相對人發現處分作成後始存在之有利新證據，得申請程序重開", "相對人有程序重開事由，因重大過失而未能在救濟程序中主張，仍得申請程序重開", "相對人自法定救濟期間經過後已逾2年，不得申請程序重開", "程序重開僅限於相對人始得申請"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "402", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL)
